      {
        "name": "per_page",
        "in": "query",
        "required": false,
        "schema": {
          "type": "integer",
          "format": "int64",
          "default": 25,
          "example": 25
        },
        "description": "Maximum number of entries returned per page. For more information, see \"[Pagination](#description/pagination)\"."
      }
